  "sourcesContent": [".page { display:flex;flex-direction:column;gap:24px; }\r\n.page-header { display:flex;align-items:flex-start;justify-content:space-between;flex-wrap:wrap;gap:12px; }\r\n.page-sub { color:var(--text-secondary);margin-top:4px; }\r\n.cal-layout { display:grid;grid-template-columns:1fr 260px;gap:18px;align-items:start; }\r\n@media(max-width:900px) { .cal-layout { grid-template-columns:1fr; } }\r\n.cal-card { padding:20px; }\r\n.cal-nav { display:flex;align-items:center;justify-content:space-between;margin-bottom:18px; }\r\n.cal-month { font-family:'Plus Jakarta Sans',sans-serif;font-size:16px;font-weight:800; }\r\n.nav-btn { background:none;border:none;font-size:20px;cursor:pointer;color:var(--text-secondary);padding:4px 10px;border-radius:8px;transition:all 0.15s; }\r\n.nav-btn:hover { background:var(--orange-light);color:var(--orange); }\r\n.cal-days-header { display:grid;grid-template-columns:repeat(7,1fr);gap:2px;margin-bottom:4px; }\r\n.cal-days-header span { text-align:center;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.06em;color:var(--text-muted);padding:4px; }\r\n.cal-grid { display:grid;grid-template-columns:repeat(7,1fr);gap:2px; }\r\n.cal-cell { min-height:80px;padding:6px;border-radius:8px;cursor:pointer;transition:background 0.15s;border:1px solid transparent; }\r\n.cal-cell:hover:not(.empty) { background:var(--orange-light);border-color:rgba(232,98,42,0.2); }\r\n.cal-cell.empty { cursor:default;opacity:0.25; }\r\n.cal-cell.today { background:var(--orange-light);border-color:rgba(232,98,42,0.3); }\r\n.cal-cell.today .cal-day-num { background:var(--orange);color:white;border-radius:50%;width:22px;height:22px;display:flex;align-items:center;justify-content:center;font-weight:700; }\r\n.cal-day-num { font-size:12px;font-weight:600;color:var(--text-primary);margin-bottom:3px; }\r\n.cal-event-pill { font-size:9px;font-weight:600;padding:2px 5px;border-radius:4px;margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis; }\r\n.more-events { font-size:9px;color:var(--text-muted);font-weight:600;margin-top:2px; }\r\n.sidebar-events { display:flex;flex-direction:column;gap:14px; }\r\n.upcoming-card { padding:18px; }\r\n.legend-card { padding:16px; }\r\n.upcoming-item { display:flex;align-items:flex-start;gap:10px;padding:8px 0;border-bottom:1px solid var(--border); }\r\n.upcoming-item:last-child { border-bottom:none; }\r\n.upcoming-bar { width:3px;height:36px;border-radius:99px;flex-shrink:0;margin-top:2px; }\r\n.upcoming-title { font-size:12px;font-weight:600;color:var(--text-primary); }\r\n.upcoming-date { font-size:11px;color:var(--text-muted);margin-top:3px; }\r\n.legend-item { display:flex;align-items:center;gap:8px;font-size:12px;color:var(--text-secondary);margin-bottom:7px; }\r\n.legend-dot { width:10px;height:10px;border-radius:50%; }\r\n"],
